export interface SpellData {
  name: string
  level: number       // 0 = cantrip
  school: string
  castingTime: string
  range: string
  components: string
  duration: string
  description: string
}

export function findSpell(name: string): SpellData | undefined {
  return SPELLS.find(s => s.name.toLowerCase() === name.toLowerCase())
}

